import React, { useState } from "react";

const COLORS = {
  red: "#B80000",
  gold: "#D4A017",
  white: "#FFFFFF",
  lightGray: "#F4F4F4",
  darkText: "#222222",
};

const INCIDENT_TYPES = [
  "Basura acumulada",
  "Lote abandonado",
  "Daño en vía pública",
  "Alumbrado defectuoso",
  "Riesgo para peatones",
  "Otro",
];

function App() {
  const [view, setView] = useState("home");
  const [formData, setFormData] = useState({
    type: "",
    description: "",
    location: "",
    contact: "",
  });

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData((prev) => ({
      ...prev,
      [name]: value,
    }));
  };

  const handleSubmit = (e) => {
    e.preventDefault();

    if (!formData.type || !formData.description || !formData.location) {
      alert("Por favor completa al menos: tipo, descripción y ubicación.");
      return;
    }

    console.log("REPORTE ENVIADO (simulado):", formData);

    alert("Reporte registrado (simulado). Más adelante se enviará al servidor.");

    setFormData({
      type: "",
      description: "",
      location: "",
      contact: "",
    });
    setView("home");
  };

  const renderHome = () => (
    <main
      style={{
        flex: 1,
        display: "flex",
        flexDirection: "column",
        justifyContent: "center",
        alignItems: "center",
        textAlign: "center",
        padding: "2rem 1rem",
      }}
    >
      <h1
        style={{
          color: COLORS.red,
          fontSize: "2.4rem",
          marginBottom: "0.5rem",
        }}
      >
        ¡BALBOA ALERTA ESTÁ VIVO!
      </h1>

      <p
        style={{
          color: COLORS.darkText,
          maxWidth: "520px",
          fontSize: "1rem",
          marginBottom: "2rem",
        }}
      >
        Vecinos organizados reportando basura, daños, riesgos y problemas en
        tiempo real. Un distrito más limpio, más seguro, más nuestro.
      </p>

      <button
        style={{
          padding: "1rem 2.5rem",
          fontSize: "1.2rem",
          fontWeight: "bold",
          borderRadius: "999px",
          border: "none",
          backgroundColor: COLORS.red,
          color: COLORS.white,
          cursor: "pointer",
          boxShadow: "0 4px 10px rgba(0,0,0,0.15)",
        }}
        onClick={() => setView("report")}
      >
        Reportar incidencia
      </button>
    </main>
  );

  const renderForm = () => (
    <main
      style={{
        flex: 1,
        display: "flex",
        justifyContent: "center",
        alignItems: "center",
        padding: "2rem 1rem",
      }}
    >
      <div
        style={{
          width: "100%",
          maxWidth: "540px",
          backgroundColor: COLORS.white,
          borderRadius: "12px",
          boxShadow: "0 4px 16px rgba(0,0,0,0.1)",
          padding: "1.8rem 1.6rem",
          borderTop: `5px solid ${COLORS.red}`,
        }}
      >
        <h2
          style={{
            marginTop: 0,
            marginBottom: "0.5rem",
            color: COLORS.red,
          }}
        >
          Nuevo reporte ciudadano
        </h2>
        <p
          style={{
            marginTop: 0,
            marginBottom: "1.2rem",
            fontSize: "0.9rem",
            color: COLORS.darkText,
          }}
        >
          Describe el problema con claridad. Esta información será la base para
          priorizar acciones en el territorio.
        </p>

        <form onSubmit={handleSubmit}>
          {/* Tipo */}
          <div style={{ marginBottom: "1rem" }}>
            <label
              style={{ display: "block", marginBottom: "0.3rem", fontSize: "0.9rem" }}
            >
              Tipo de incidencia <span style={{ color: COLORS.red }}>*</span>
            </label>
            <select
              name="type"
              value={formData.type}
              onChange={handleChange}
              style={{
                width: "100%",
                padding: "0.6rem",
                borderRadius: "6px",
                border: "1px solid #ccc",
              }}
            >
              <option value="">Selecciona una opción</option>
              {INCIDENT_TYPES.map((t) => (
                <option key={t} value={t}>
                  {t}
                </option>
              ))}
            </select>
          </div>

          {/* Descripción */}
          <div style={{ marginBottom: "1rem" }}>
            <label
              style={{ display: "block", marginBottom: "0.3rem", fontSize: "0.9rem" }}
            >
              Descripción del problema{" "}
              <span style={{ color: COLORS.red }}>*</span>
            </label>
            <textarea
              name="description"
              value={formData.description}
              onChange={handleChange}
              rows={4}
              placeholder="Ejemplo: Basura acumulada desde hace 3 semanas, genera malos olores y moscas."
              style={{
                width: "100%",
                padding: "0.6rem",
                borderRadius: "6px",
                border: "1px solid #ccc",
                resize: "vertical",
              }}
            />
          </div>

          {/* Ubicación */}
          <div style={{ marginBottom: "1rem" }}>
            <label
              style={{ display: "block", marginBottom: "0.3rem", fontSize: "0.9rem" }}
            >
              Ubicación aproximada{" "}
              <span style={{ color: COLORS.red }}>*</span>
            </label>
            <input
              type="text"
              name="location"
              value={formData.location}
              onChange={handleChange}
              placeholder="Calle, referencia cercana, barrio."
              style={{
                width: "100%",
                padding: "0.6rem",
                borderRadius: "6px",
                border: "1px solid #ccc",
              }}
            />
          </div>

          {/* Contacto opcional */}
          <div style={{ marginBottom: "1.4rem" }}>
            <label
              style={{ display: "block", marginBottom: "0.3rem", fontSize: "0.9rem" }}
            >
              Contacto (opcional)
            </label>
            <input
              type="text"
              name="contact"
              value={formData.contact}
              onChange={handleChange}
              placeholder="Nombre o teléfono para aclaraciones (opcional)."
              style={{
                width: "100%",
                padding: "0.6rem",
                borderRadius: "6px",
                border: "1px solid #ccc",
              }}
            />
          </div>

          {/* Botones */}
          <div
            style={{
              display: "flex",
              justifyContent: "space-between",
              gap: "0.8rem",
            }}
          >
            <button
              type="button"
              onClick={() => setView("home")}
              style={{
                flex: 1,
                padding: "0.7rem 1rem",
                borderRadius: "999px",
                border: `1px solid ${COLORS.red}`,
                backgroundColor: COLORS.white,
                color: COLORS.red,
                fontWeight: "bold",
                cursor: "pointer",
              }}
            >
              Cancelar
            </button>
            <button
              type="submit"
              style={{
                flex: 1,
                padding: "0.7rem 1rem",
                borderRadius: "999px",
                border: "none",
                backgroundColor: COLORS.red,
                color: COLORS.white,
                fontWeight: "bold",
                cursor: "pointer",
              }}
            >
              Enviar reporte
            </button>
          </div>
        </form>
      </div>
    </main>
  );

  return (
    <div
      style={{
        minHeight: "100vh",
        display: "flex",
        flexDirection: "column",
        backgroundColor: COLORS.lightGray,
        fontFamily: "Arial, sans-serif",
      }}
    >
      {/* HEADER */}
      <header
        style={{
          backgroundColor: COLORS.white,
          borderBottom: `3px solid ${COLORS.red}`,
          padding: "1rem 2rem",
          display: "flex",
          justifyContent: "space-between",
          alignItems: "center",
        }}
      >
        <div
          style={{
            fontWeight: "bold",
            fontSize: "1.4rem",
            color: COLORS.red,
          }}
        >
          BALBOA ALERTA
        </div>
        <div
          style={{
            fontSize: "0.9rem",
            color: COLORS.darkText,
            borderLeft: `3px solid ${COLORS.gold}`,
            paddingLeft: "0.7rem",
          }}
        >
          Plataforma ciudadana de reportes locales
        </div>
      </header>

      {/* VISTA DINÁMICA */}
      {view === "home" ? renderHome() : renderForm()}

      {/* FOOTER */}
      <footer
        style={{
          backgroundColor: COLORS.white,
          borderTop: `2px solid ${COLORS.gold}`,
          padding: "0.7rem 1.5rem",
          fontSize: "0.8rem",
          color: COLORS.darkText,
          textAlign: "center",
        }}
      >
        Balboa Alerta · Iniciativa ciudadana para La Chorrera
      </footer>
    </div>
  );
}

export default App;
